class Chronometre extends StatefulWidget {
  @override
  _ChronometreState createState() => _ChronometreState();
}

class _ChronometreState extends State<Chronometre> {
  int secondes = 0;
  late Timer timer;

  @override
  void initState() {
    super.initState();
    timer = Timer.periodic(Duration(seconds: 1), (t) {
      setState(() {
        secondes++;
      });
    });
  }

  @override
  void dispose() {
    timer.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      body: Center(
        child: Text('$secondes secondes'),
      ),
    );
  }
}
