class CustomSliderControl extends StatefulWidget {
  @override
  _CustomSliderControlState createState() => _CustomSliderControlState();
}

class _CustomSliderControlState extends State<CustomSliderControl> {
  double valeur = 50.0;
  final TextEditingController _controller = TextEditingController();

  @override
  void initState() {
    super.initState();
    _controller.text = valeur.toInt().toString();
  }

  void _mettreAJourValeur(double nouvelleValeur) {
    setState(() {
      valeur = nouvelleValeur;
      _controller.text = valeur.toInt().toString();
    });
  }

  void _validerTexte() {
    final texte = _controller.text;
    final nouvelleValeur = int.tryParse(texte);
    if (nouvelleValeur != null && nouvelleValeur >= 0 && nouvelleValeur <= 100) {
      _mettreAJourValeur(nouvelleValeur.toDouble());
    } else {
      _controller.text = valeur.toInt().toString();
      ScaffoldMessenger.of(context).showSnackBar(
        SnackBar(content: Text('Valeur invalide (0-100)')),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Column(
      mainAxisAlignment: MainAxisAlignment.center,
      children: [
        Text('Valeur actuelle : ${valeur.toInt()}', style: TextStyle(fontSize: 32)),
        Slider(
          value: valeur,
          min: 0,
          max: 100,
          divisions: 100,
          onChanged: (nouvelleValeur) => _mettreAJourValeur(nouvelleValeur),
        ),
        SizedBox(height: 20),
        Row(children: [
          Expanded(
            child: TextField(
              controller: _controller,
              keyboardType: TextInputType.number,
              decoration: InputDecoration(labelText: 'Saisir une valeur'),
              onSubmitted: (_) => _validerTexte(),
            ),
          ),
          ElevatedButton(
            onPressed: _validerTexte,
            child: Text('OK'),
          ),
        ]),
      ],
    );
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }
}
